export function normalizeResidentialCountry(country: string): string {
  const c = (country || "").trim();
  if (c === "United Arab Emirates" || c === "UAE") return "UAE";
  if (c === "Saudi Arabia" || c === "KSA") return "Saudi Arabia";
  return c;
}

